from decimal import Decimal, ROUND_HALF_UP


def minor_unit(currency):
    if currency.upper() == "JPY":
        return Decimal("1")
    return Decimal("0.01")


def round_minor(amount, currency):
    return Decimal(amount).quantize(minor_unit(currency), rounding=ROUND_HALF_UP)
